import { User, Patient, Doctor, Admin, UserRole, ApiResponse } from '@/types';
import { mockPatients, mockDoctors, mockAdmins } from '@/data/mockData';
import { apiSuccess, apiError } from './api';

// Mock user credentials
const mockCredentials: Record<string, { password: string; userId: string; role: UserRole }> = {
  'patient@demo.com': { password: 'demo123', userId: 'patient-1', role: 'patient' },
  'doctor@demo.com': { password: 'demo123', userId: 'doctor-1', role: 'doctor' },
  'admin@demo.com': { password: 'demo123', userId: 'admin-1', role: 'admin' },
};

export interface LoginCredentials {
  email: string;
  password: string;
}

export interface RegisterData {
  email: string;
  password: string;
  name: string;
  role: UserRole;
  phone?: string;
}

export const authService = {
  async login(credentials: LoginCredentials): Promise<ApiResponse<User | null>> {
    const { email, password } = credentials;
    const userCred = mockCredentials[email.toLowerCase()];

    if (!userCred || userCred.password !== password) {
      return apiError('Invalid email or password');
    }

    let user: User | undefined;
    switch (userCred.role) {
      case 'patient':
        user = mockPatients.find(p => p.id === userCred.userId);
        break;
      case 'doctor':
        user = mockDoctors.find(d => d.id === userCred.userId);
        break;
      case 'admin':
        user = mockAdmins.find(a => a.id === userCred.userId);
        break;
    }

    if (!user) {
      return apiError('User not found');
    }

    // Store in localStorage for persistence
    localStorage.setItem('currentUser', JSON.stringify(user));
    
    return apiSuccess(user, 'Login successful');
  },

  async loginAsRole(role: UserRole): Promise<ApiResponse<User>> {
    let user: User | undefined;
    
    switch (role) {
      case 'patient':
        user = mockPatients[0];
        break;
      case 'doctor':
        user = mockDoctors[0];
        break;
      case 'admin':
        user = mockAdmins[0];
        break;
    }

    if (!user) {
      return apiError('User not found');
    }

    localStorage.setItem('currentUser', JSON.stringify(user));
    return apiSuccess(user, `Logged in as ${role}`);
  },

  async logout(): Promise<ApiResponse<null>> {
    localStorage.removeItem('currentUser');
    return apiSuccess(null, 'Logged out successfully');
  },

  async register(data: RegisterData): Promise<ApiResponse<User>> {
    // Check if email already exists
    const existingUser = Object.keys(mockCredentials).includes(data.email.toLowerCase());
    if (existingUser) {
      return apiError('Email already registered');
    }

    const newUser: Patient = {
      id: `patient-${Date.now()}`,
      email: data.email,
      name: data.name,
      role: 'patient',
      phone: data.phone,
      createdAt: new Date().toISOString(),
    };

    localStorage.setItem('currentUser', JSON.stringify(newUser));
    return apiSuccess(newUser, 'Registration successful');
  },

  async getCurrentUser(): Promise<ApiResponse<User | null>> {
    const stored = localStorage.getItem('currentUser');
    if (!stored) {
      return apiSuccess(null);
    }

    try {
      const user = JSON.parse(stored) as User;
      return apiSuccess(user);
    } catch {
      return apiSuccess(null);
    }
  },

  async updateProfile(userId: string, data: Partial<User>): Promise<ApiResponse<User>> {
    const stored = localStorage.getItem('currentUser');
    if (!stored) {
      return apiError('Not authenticated');
    }

    const user = JSON.parse(stored) as User;
    const updatedUser = { ...user, ...data };
    localStorage.setItem('currentUser', JSON.stringify(updatedUser));
    
    return apiSuccess(updatedUser, 'Profile updated');
  },
};
