import { ApiResponse, PaginatedResponse } from '@/types';

// Simulated network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Random delay between min and max ms
const randomDelay = (min: number = 200, max: number = 800) => 
  delay(Math.floor(Math.random() * (max - min + 1)) + min);

// Simulate API success response
export async function apiSuccess<T>(data: T, message?: string): Promise<ApiResponse<T>> {
  await randomDelay();
  return {
    data,
    success: true,
    message,
  };
}

// Simulate API error response
export async function apiError<T>(error: string): Promise<ApiResponse<T>> {
  await randomDelay();
  return {
    data: null as T,
    success: false,
    error,
  };
}

// Simulate paginated response
export async function paginatedSuccess<T>(
  data: T[],
  page: number,
  limit: number,
  total: number
): Promise<PaginatedResponse<T>> {
  await randomDelay();
  return {
    data,
    success: true,
    page,
    limit,
    total,
    totalPages: Math.ceil(total / limit),
  };
}

